    }
    )
    }
    

    
    /**
     * Update the phone's power state from the native layer.
     *
     * Called by the Android/iOS battery manager whenever the charging state
     * or battery level changes. This triggers a re-evaluation of whether
     * mining conditions are met.
     */
    @Throws(FfiException::class)override fun `updatePowerState`(`isPluggedIn`: kotlin.Boolean, `batteryPercent`: kotlin.UByte): FfiMiningStatus {
            return FfiConverterTypeFfiMiningStatus.lift(
    callWithPointer {
    uniffiRustCallWithError(FfiException) { _status ->
    UniffiLib.INSTANCE.uniffi_gratia_ffi_fn_method_gratianode_update_power_state(
        it, FfiConverterBoolean.lower(`isPluggedIn`),FfiConverterUByte.lower(`batteryPercent`),_status)
}
    }
    )
    }
    

    

    
    
    companion object
    
}

/**
 * @suppress
 */
public object FfiConverterTypeGratiaNode: FfiConverter<GratiaNode, Pointer> {

    override fun lower(value: GratiaNode): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): GratiaNode {
        return GratiaNode(value)
    }

    override fun read(buf: ByteBuffer): GratiaNode {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: GratiaNode) = 8UL

    override fun write(value: GratiaNode, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



