/**
 * User-friendly error type exposed across the FFI boundary.
 *
 * Variants are kept simple and descriptive — mobile UI code switches on the
 * variant name to decide what to show the user (e.g., a "battery too low"
 * toast vs. a "wallet locked" dialog).
 */
sealed class FfiException: kotlin.Exception() {
    
    class WalletNotInitialized(
        ) : FfiException() {
        override val message
            get() = ""
    }
    
    class WalletAlreadyExists(
        ) : FfiException() {
        override val message
            get() = ""
    }
    
    class InvalidAddress(
        
        val `reason`: kotlin.String
        ) : FfiException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class InsufficientBalance(
        
        val `availableLux`: kotlin.ULong, 
        
        val `requiredLux`: kotlin.ULong
        ) : FfiException() {
        override val message
            get() = "availableLux=${ `availableLux` }, requiredLux=${ `requiredLux` }"
    }
    
    class MiningNotAvailable(
        
        val `reason`: kotlin.String
        ) : FfiException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class StakingException(
        
        val `reason`: kotlin.String
        ) : FfiException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class ProofOfLifeException(
        
        val `reason`: kotlin.String
        ) : FfiException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class WalletFrozen(
        ) : FfiException() {
        override val message
            get() = ""
    }
    
    class NetworkException(
        
        val `reason`: kotlin.String
        ) : FfiException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    
    class InternalException(
        
        val `reason`: kotlin.String
        ) : FfiException() {
        override val message
            get() = "reason=${ `reason` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<FfiException> {
        override fun lift(error_buf: RustBuffer.ByValue): FfiException = FfiConverterTypeFfiError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeFfiError : FfiConverterRustBuffer<FfiException> {
    override fun read(buf: ByteBuffer): FfiException {
        

        return when(buf.getInt()) {
            1 -> FfiException.WalletNotInitialized()
            2 -> FfiException.WalletAlreadyExists()
            3 -> FfiException.InvalidAddress(
                FfiConverterString.read(buf),
                )
            4 -> FfiException.InsufficientBalance(
                FfiConverterULong.read(buf),
                FfiConverterULong.read(buf),
                )
            5 -> FfiException.MiningNotAvailable(
                FfiConverterString.read(buf),
                )
            6 -> FfiException.StakingException(
                FfiConverterString.read(buf),
                )
            7 -> FfiException.ProofOfLifeException(
                FfiConverterString.read(buf),
                )
            8 -> FfiException.WalletFrozen()
            9 -> FfiException.NetworkException(
                FfiConverterString.read(buf),
                )
            10 -> FfiException.InternalException(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: FfiException): ULong {
        return when(value) {
            is FfiException.WalletNotInitialized -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is FfiException.WalletAlreadyExists -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is FfiException.InvalidAddress -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is FfiException.InsufficientBalance -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterULong.allocationSize(value.`availableLux`)
                + FfiConverterULong.allocationSize(value.`requiredLux`)
            )
            is FfiException.MiningNotAvailable -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is FfiException.StakingException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is FfiException.ProofOfLifeException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is FfiException.WalletFrozen -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is FfiException.NetworkException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
            is FfiException.InternalException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`reason`)
            )
        }
    }

    override fun write(value: FfiException, buf: ByteBuffer) {
        when(value) {
            is FfiException.WalletNotInitialized -> {
                buf.putInt(1)
                Unit
            }
            is FfiException.WalletAlreadyExists -> {
                buf.putInt(2)
                Unit
            }
            is FfiException.InvalidAddress -> {
                buf.putInt(3)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is FfiException.InsufficientBalance -> {
                buf.putInt(4)
                FfiConverterULong.write(value.`availableLux`, buf)
                FfiConverterULong.write(value.`requiredLux`, buf)
                Unit
            }
            is FfiException.MiningNotAvailable -> {
                buf.putInt(5)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is FfiException.StakingException -> {
                buf.putInt(6)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is FfiException.ProofOfLifeException -> {
                buf.putInt(7)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is FfiException.WalletFrozen -> {
                buf.putInt(8)
                Unit
            }
            is FfiException.NetworkException -> {
                buf.putInt(9)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
            is FfiException.InternalException -> {
                buf.putInt(10)
                FfiConverterString.write(value.`reason`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



