     */
    data class TransactionReceived(
        val `hashHex`: kotlin.String) : FfiNetworkEvent() {
        companion object
    }
    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeFfiNetworkEvent : FfiConverterRustBuffer<FfiNetworkEvent>{
    override fun read(buf: ByteBuffer): FfiNetworkEvent {
        return when(buf.getInt()) {
            1 -> FfiNetworkEvent.PeerConnected(
                FfiConverterString.read(buf),
                )
            2 -> FfiNetworkEvent.PeerDisconnected(
                FfiConverterString.read(buf),
                )
            3 -> FfiNetworkEvent.BlockReceived(
                FfiConverterULong.read(buf),
                FfiConverterString.read(buf),
                )
            4 -> FfiNetworkEvent.TransactionReceived(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: FfiNetworkEvent) = when(value) {
        is FfiNetworkEvent.PeerConnected -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`peerId`)
            )
        }
        is FfiNetworkEvent.PeerDisconnected -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`peerId`)
            )
        }
        is FfiNetworkEvent.BlockReceived -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterULong.allocationSize(value.`height`)
                + FfiConverterString.allocationSize(value.`producer`)
            )
        }
        is FfiNetworkEvent.TransactionReceived -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`hashHex`)
            )
        }
    }

    override fun write(value: FfiNetworkEvent, buf: ByteBuffer) {
        when(value) {
            is FfiNetworkEvent.PeerConnected -> {
                buf.putInt(1)
                FfiConverterString.write(value.`peerId`, buf)
                Unit
            }
            is FfiNetworkEvent.PeerDisconnected -> {
                buf.putInt(2)
                FfiConverterString.write(value.`peerId`, buf)
                Unit
            }
            is FfiNetworkEvent.BlockReceived -> {
                buf.putInt(3)
                FfiConverterULong.write(value.`height`, buf)
                FfiConverterString.write(value.`producer`, buf)
                Unit
            }
            is FfiNetworkEvent.TransactionReceived -> {
                buf.putInt(4)
                FfiConverterString.write(value.`hashHex`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}





/**
 * Sensor events pushed from the native platform layer (Android/iOS) into
 * the Rust PoL engine.
 *
 * WHY: This enum mirrors `gratia_pol::collector::SensorEvent` but strips
 * out the `DateTime<Utc>` timestamp field (which is not FFI-safe). The
 * timestamp is set to `Utc::now()` on the Rust side when the event arrives.
 */
sealed class FfiSensorEvent {
    
    /**
     * Phone was unlocked by the user.
     */
    object Unlock : FfiSensorEvent()
    
    
    /**
     * A screen interaction session was recorded.
     */
    data class Interaction(
        /**
         * Duration of the session in seconds.
         */
        val `durationSecs`: kotlin.UInt) : FfiSensorEvent() {
        companion object
    }
    
    /**
     * Phone orientation changed (picked up, rotated, set down).
     */
    object OrientationChange : FfiSensorEvent()
    
    
    /**
     * Accelerometer detected human-consistent motion.
     */
    object Motion : FfiSensorEvent()
    
    
    /**
     * A GPS fix was obtained.
     */
    data class GpsUpdate(
        val `lat`: kotlin.Float, 
        val `lon`: kotlin.Float) : FfiSensorEvent() {
        companion object
    }
    
    /**
     * Wi-Fi scan completed with visible BSSIDs (as opaque hashes).
     */
    data class WifiScan(
        val `bssidHashes`: List<kotlin.ULong>) : FfiSensorEvent() {
        companion object
    }
    
    /**
     * Bluetooth scan completed with nearby peers (as opaque hashes).
     */
    data class BluetoothScan(
        val `peerHashes`: List<kotlin.ULong>) : FfiSensorEvent() {
        companion object
    }
    
    /**
     * Charge state changed (plugged in or unplugged).
     */
    data class ChargeEvent(
        val `isCharging`: kotlin.Boolean) : FfiSensorEvent() {
        companion object
    }
    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeFfiSensorEvent : FfiConverterRustBuffer<FfiSensorEvent>{
    override fun read(buf: ByteBuffer): FfiSensorEvent {
        return when(buf.getInt()) {
            1 -> FfiSensorEvent.Unlock
            2 -> FfiSensorEvent.Interaction(
                FfiConverterUInt.read(buf),
                )
            3 -> FfiSensorEvent.OrientationChange
            4 -> FfiSensorEvent.Motion
            5 -> FfiSensorEvent.GpsUpdate(
                FfiConverterFloat.read(buf),
                FfiConverterFloat.read(buf),
                )
            6 -> FfiSensorEvent.WifiScan(
                FfiConverterSequenceULong.read(buf),
                )
            7 -> FfiSensorEvent.BluetoothScan(
                FfiConverterSequenceULong.read(buf),
                )
            8 -> FfiSensorEvent.ChargeEvent(
                FfiConverterBoolean.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: FfiSensorEvent) = when(value) {
        is FfiSensorEvent.Unlock -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is FfiSensorEvent.Interaction -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterUInt.allocationSize(value.`durationSecs`)
            )
        }
        is FfiSensorEvent.OrientationChange -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is FfiSensorEvent.Motion -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is FfiSensorEvent.GpsUpdate -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterFloat.allocationSize(value.`lat`)
                + FfiConverterFloat.allocationSize(value.`lon`)
            )
        }
        is FfiSensorEvent.WifiScan -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterSequenceULong.allocationSize(value.`bssidHashes`)
            )
        }
        is FfiSensorEvent.BluetoothScan -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterSequenceULong.allocationSize(value.`peerHashes`)
            )
        }
        is FfiSensorEvent.ChargeEvent -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterBoolean.allocationSize(value.`isCharging`)
            )
        }
    }

    override fun write(value: FfiSensorEvent, buf: ByteBuffer) {
        when(value) {
            is FfiSensorEvent.Unlock -> {
                buf.putInt(1)
                Unit
            }
            is FfiSensorEvent.Interaction -> {
                buf.putInt(2)
                FfiConverterUInt.write(value.`durationSecs`, buf)
                Unit
            }
            is FfiSensorEvent.OrientationChange -> {
                buf.putInt(3)
                Unit
            }
            is FfiSensorEvent.Motion -> {
                buf.putInt(4)
                Unit
            }
            is FfiSensorEvent.GpsUpdate -> {
                buf.putInt(5)
                FfiConverterFloat.write(value.`lat`, buf)
                FfiConverterFloat.write(value.`lon`, buf)
                Unit
            }
            is FfiSensorEvent.WifiScan -> {
                buf.putInt(6)
                FfiConverterSequenceULong.write(value.`bssidHashes`, buf)
                Unit
            }
            is FfiSensorEvent.BluetoothScan -> {
                buf.putInt(7)
                FfiConverterSequenceULong.write(value.`peerHashes`, buf)
                Unit
            }
            is FfiSensorEvent.ChargeEvent -> {
                buf.putInt(8)
                FfiConverterBoolean.write(value.`isCharging`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}






/**
 * @suppress
 */
public object FfiConverterOptionalString: FfiConverterRustBuffer<kotlin.String?> {
    override fun read(buf: ByteBuffer): kotlin.String? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterString.read(buf)
    }

    override fun allocationSize(value: kotlin.String?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterString.allocationSize(value)
        }
    }

    override fun write(value: kotlin.String?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterString.write(value, buf)
        }
    }
}




/**
 * @suppress
 */
public object FfiConverterSequenceULong: FfiConverterRustBuffer<List<kotlin.ULong>> {
    override fun read(buf: ByteBuffer): List<kotlin.ULong> {
        val len = buf.getInt()
        return List<kotlin.ULong>(len) {
            FfiConverterULong.read(buf)
        }
    }

    override fun allocationSize(value: List<kotlin.ULong>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterULong.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<kotlin.ULong>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterULong.write(it, buf)
        }
    }
}




